-- Do not edit this file directly.
-- Contract precedence: mirrored SQL is the exact audit source within backend-truth.
-- Source: supabase/migrations/20260712130200_sync_estimate_projection_rpc.sql
-- Regenerate with: node scripts/generate-backend-truth.mjs
-- Sync stabilization P1: the server-side estimate→domains projection.
--
-- sync_estimate_projection(p_project_id, p_client_revision) is an atomic port of
-- the client pipeline (rovno: planning-source.syncProjectTasksFromEstimate →
-- procurement-source.syncProjectProcurementFromEstimate →
-- hr-source.syncProjectHRFromEstimate). It reads the SERVER draft tables — never a
-- client snapshot — so a stale call can never write stale data; concurrent calls
-- serialize on a per-project advisory lock and each projects current server truth.
--
-- Parity contract with the client pipeline (pinned by
-- supabase/tests/estimate_projection.test.sql):
--   * planning status → no-op (execution_status, with the approved→in_work
--     inference fallback from 20260611120000).
--   * empty draft (no stages, no works, no lines) → no-op, never mass-unlinks.
--   * unlink-don't-delete for rows that lose their estimate source: tasks lose
--     estimate_work_id only; procurement/HR lose lineage columns only. Deleted
--     estimate lines additionally clean their projection-owned downstream
--     lineage via the BEFORE DELETE trigger below (the FK SET NULL would
--     otherwise erase the only identifier before any cleanup could run).
--   * task identity: existing task by estimate_work_id, else the task derived
--     from checklist lineage (how the client itself rehydrates hero-created
--     tasks), else the hero-transition task map, else id = work id.
--   * human-owned fields are never overwritten: task status/description/
--     created_by/completed_at; checklist is_done/procurement_item_id;
--     procurement status/description/category/notes/actuals/received/created_by
--     (created_by preservation is a deliberate deviation from the legacy client,
--     which overwrote it only to satisfy RLS); HR status/compensation_type/
--     description/actual_cost_cents/created_by; procurement unit survives a
--     null estimate unit.
--   * estimate-driven fields always overwrite: titles, stage/task lineage,
--     dates, quantities, planned money, checklist sort order (two-phase
--     renumber under the immediate UNIQUE (task_id, sort_order)).
--   * assignee collapse: task assignee = first labor/subcontractor line (by
--     created_at, id) with a non-null assignee_profile_id; NULL clears.
--   * HR rows only for labor/subcontractor lines whose work got a task;
--     hr_item_assignees reconciled to the line assignee (label-only clears).
--
-- SECURITY (fail-closed identity adoption): estimate work/line UUIDs are
-- client-writable, so deterministic target ids could collide with rows the
-- caller must not touch. Every adoption is validated to belong to
-- p_project_id with compatible lineage BEFORE the write, every ON CONFLICT
-- update carries a same-project guard (a hostile collision then errors on the
-- subsequent FK/lineage step instead of adopting), project_id is never moved
-- by adoption, and hero-map candidates that fail validation are discarded
-- entirely (never reused as new-row ids). Hero maps come from the latest
-- hero-transition activity event and are treated as UNTRUSTED input: every
-- JSON level is typeof-validated and malformed payloads are ignored.
--
-- Auth: can_manage_project (owner / co-owner) — matching both the client-side
-- projection gate (estimate editing is owner/co-owner) and the HR write
-- boundary (contractors must not mutate HR; 20260409140000).
--
-- Works with a NULL project_stage_id cannot be projected (tasks.stage_id is
-- NOT NULL and the tasks lineage trigger requires stage_id = the work's
-- stage); they are skipped and reported in skipped_work_ids.

-- ---------------------------------------------------------------------------
-- Deleted estimate lines: clean projection-owned downstream lineage while
-- OLD.id is still available (the FKs are ON DELETE SET NULL and would erase
-- the only identifier). Checklist rows are projection-owned and are deleted;
-- procurement/HR rows are user data and only lose projection lineage.
-- ---------------------------------------------------------------------------

create or replace function public.unlink_projection_lineage_on_line_delete()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
begin
  delete from public.task_checklist_items ci
  where ci.estimate_resource_line_id = old.id;

  -- estimate_resource_line_id must be nulled in the SAME update: during a
  -- cascade (work/version/estimate delete) the parent rows are already gone,
  -- so an update that leaves the line id set trips
  -- enforce_hr_item_estimate_lineage_scope's existence join and aborts the
  -- whole delete. Nulling it here also pre-empts the FK SET NULL.
  update public.procurement_items pi
  set estimate_resource_line_id = null, task_id = null
  where pi.estimate_resource_line_id = old.id;

  update public.hr_items hi
  set estimate_resource_line_id = null, estimate_work_id = null, task_id = null
  where hi.estimate_resource_line_id = old.id;

  return old;
end;
$$;

revoke all on function public.unlink_projection_lineage_on_line_delete() from public;

create trigger unlink_projection_lineage_on_line_delete
  before delete on public.estimate_resource_lines
  for each row execute function public.unlink_projection_lineage_on_line_delete();

-- ---------------------------------------------------------------------------
-- The projection RPC.
-- ---------------------------------------------------------------------------

drop function if exists public.sync_estimate_projection(uuid, text);

create function public.sync_estimate_projection(
  p_project_id uuid,
  p_client_revision text default null
) returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_uid uuid := auth.uid();
  v_root public.project_estimates%rowtype;
  v_root_count integer := 0;
  v_row_rec record;
  v_status text;
  v_version_id uuid;
  v_work_count integer;
  v_hero_ids jsonb;
  v_hero_line_map jsonb := '{}'::jsonb;
  v_hero_proc_map jsonb := '{}'::jsonb;
  v_hero_hr_map jsonb := '{}'::jsonb;
  v_hero_task_map jsonb := '{}'::jsonb;
  v_hero_work_map jsonb := '{}'::jsonb;
  v_task_map jsonb := '{}'::jsonb;
  v_skipped_work_ids uuid[] := '{}';
  v_stale_task_ids uuid[] := '{}';
  v_active_task_ids uuid[] := '{}';
  v_work record;
  v_line record;
  v_row record;
  v_assignee uuid;
  v_task_id uuid;
  v_existing_id uuid;
  v_candidate uuid;
  v_candidate_project uuid;
  v_candidate_work uuid;
  v_candidate_line uuid;
  v_derived_count integer;
  v_lineage_count integer;
  v_desired_count integer;
  v_max_sort integer;
  v_index integer;
  v_projection_seq bigint;
  v_tasks_upserted integer := 0;
  v_tasks_unlinked integer := 0;
  v_checklist_upserted integer := 0;
  v_checklist_deleted integer := 0;
  v_procurement_upserted integer := 0;
  v_procurement_unlinked integer := 0;
  v_hr_upserted integer := 0;
  v_hr_unlinked integer := 0;
  v_count integer;
  v_key text;
  v_val text;
  c_uuid_re constant text := '^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$';
begin
  if v_uid is null then
    raise exception 'must be authenticated' using errcode = '42501';
  end if;
  if p_project_id is null then
    raise exception 'invalid project id' using errcode = '22023';
  end if;
  -- The ledger CHECK caps revision at 200 chars; validate at entry so an
  -- over-long value fails fast instead of after the whole projection (the
  -- official client sends a fixed-length hash; this guards raw API callers).
  if p_client_revision is not null and char_length(p_client_revision) > 200 then
    raise exception 'client revision too long' using errcode = '22023';
  end if;
  if not public.can_manage_project(p_project_id) then
    raise exception 'insufficient permissions' using errcode = '42501';
  end if;

  -- Serialize projections and current-version flips per project (the version
  -- setter takes the SAME key). The client draft save is not under this lock;
  -- the RPC reads whatever draft state is committed.
  perform pg_advisory_xact_lock(hashtext('sync_estimate_projection:' || p_project_id::text));

  -- Single-statement root scan (no count/select race); anchored FOR UPDATE next.
  for v_row_rec in select pe.* from public.project_estimates pe where pe.project_id = p_project_id loop
    v_root_count := v_root_count + 1;
    v_root := v_row_rec;
  end loop;
  if v_root_count = 0 then
    return jsonb_build_object('status', 'skipped', 'reason', 'no_estimate', 'revision', p_client_revision);
  end if;
  if v_root_count > 1 then
    raise exception 'multiple estimate roots for project' using errcode = 'P0001';
  end if;

  select pe.* into v_root
  from public.project_estimates pe
  where pe.id = v_root.id
  for update;

  v_status := coalesce(
    v_root.execution_status,
    case when v_root.status = 'approved' then 'in_work' else 'planning' end
  );
  if v_status = 'planning' then
    return jsonb_build_object('status', 'skipped', 'reason', 'planning', 'revision', p_client_revision);
  end if;

  select ev.id into v_version_id
  from public.estimate_versions ev
  where ev.estimate_id = v_root.id and ev.is_current = true;
  if v_version_id is null then
    return jsonb_build_object('status', 'skipped', 'reason', 'no_current_version', 'revision', p_client_revision);
  end if;

  select count(*) into v_work_count from public.estimate_works ew where ew.estimate_version_id = v_version_id;

  -- Empty-draft guard, ESTIMATE-local (project stages deliberately not
  -- consulted: they persist across estimate rebuilds, so counting them would
  -- let a transiently-workless current version — e.g. a just-flipped fresh
  -- version — project as "unlink everything" and delete projection-owned
  -- checklist state). A deliberately emptied estimate still converges: the
  -- line-delete trigger and FKs unlink downstream rows at deletion time.
  if v_work_count = 0 then
    return jsonb_build_object('status', 'skipped', 'reason', 'empty_draft', 'revision', p_client_revision);
  end if;

  -- Hero-transition id maps: the durable copy of the client's localStorage
  -- cache lives in the latest hero-transition activity event payload. The
  -- table is writable by any content writer, so this is UNTRUSTED input:
  -- validate every JSON level and silently ignore anything malformed — a bad
  -- event must never block projection, and every candidate row is re-validated
  -- against project + lineage before adoption.
  select ae.payload->'ids' into v_hero_ids
  from public.activity_events ae
  where ae.project_id = p_project_id
    and ae.action_type = 'estimate.status_changed'
    and jsonb_typeof(ae.payload) = 'object'
    and ae.payload->>'source' = 'estimate_v2.hero_transition'
    and jsonb_typeof(ae.payload->'ids') = 'object'
  order by ae.created_at desc
  limit 1;

  if v_hero_ids is not null then
    if jsonb_typeof(v_hero_ids->'lineIdByLocalLineId') = 'object' then
      v_hero_line_map := v_hero_ids->'lineIdByLocalLineId';
    end if;
    if jsonb_typeof(v_hero_ids->'workIdByLocalWorkId') = 'object' then
      v_hero_work_map := v_hero_ids->'workIdByLocalWorkId';
    end if;
    if jsonb_typeof(v_hero_ids->'procurementItemIdByLocalLineId') = 'object' then
      for v_key, v_val in select * from jsonb_each_text(v_hero_ids->'procurementItemIdByLocalLineId') loop
        if v_val ~ c_uuid_re then
          v_hero_proc_map := v_hero_proc_map || jsonb_build_object(v_key, v_val);
          if (v_hero_line_map->>v_key) is not null and (v_hero_line_map->>v_key) ~ c_uuid_re then
            v_hero_proc_map := v_hero_proc_map || jsonb_build_object(v_hero_line_map->>v_key, v_val);
          end if;
        end if;
      end loop;
    end if;
    if jsonb_typeof(v_hero_ids->'hrItemIdByLocalLineId') = 'object' then
      for v_key, v_val in select * from jsonb_each_text(v_hero_ids->'hrItemIdByLocalLineId') loop
        if v_val ~ c_uuid_re then
          v_hero_hr_map := v_hero_hr_map || jsonb_build_object(v_key, v_val);
          if (v_hero_line_map->>v_key) is not null and (v_hero_line_map->>v_key) ~ c_uuid_re then
            v_hero_hr_map := v_hero_hr_map || jsonb_build_object(v_hero_line_map->>v_key, v_val);
          end if;
        end if;
      end loop;
    end if;
    if jsonb_typeof(v_hero_ids->'taskIdByLocalWorkId') = 'object' then
      for v_key, v_val in select * from jsonb_each_text(v_hero_ids->'taskIdByLocalWorkId') loop
        if v_val ~ c_uuid_re then
          v_hero_task_map := v_hero_task_map || jsonb_build_object(v_key, v_val);
          if (v_hero_work_map->>v_key) is not null and (v_hero_work_map->>v_key) ~ c_uuid_re then
            v_hero_task_map := v_hero_task_map || jsonb_build_object(v_hero_work_map->>v_key, v_val);
          end if;
        end if;
      end loop;
    end if;
  end if;

  ------------------------------------------------------------------
  -- TASKS: unlink stale, then per-work upsert (estimate-driven fields
  -- overwrite; status/description/created_by/completed_at preserved).
  ------------------------------------------------------------------
  with unlinked as (
    update public.tasks t
    set estimate_work_id = null
    where t.project_id = p_project_id
      and t.estimate_work_id is not null
      and t.estimate_work_id not in (
        select ew.id from public.estimate_works ew where ew.estimate_version_id = v_version_id
      )
    returning t.id
  )
  select coalesce(array_agg(id), '{}'), count(*) into v_stale_task_ids, v_tasks_unlinked from unlinked;

  for v_work in
    select ew.*
    from public.estimate_works ew
    where ew.estimate_version_id = v_version_id
    order by ew.sort_order, ew.id
  loop
    if v_work.project_stage_id is null then
      v_skipped_work_ids := array_append(v_skipped_work_ids, v_work.id);
      continue;
    end if;

    -- Assignee collapse: first labor/subcontractor line (created_at, id) with a
    -- profile assignee; free-text labels never reach the task row.
    select erl.assignee_profile_id into v_assignee
    from public.estimate_resource_lines erl
    where erl.estimate_work_id = v_work.id
      and erl.resource_type in ('labor', 'subcontractor')
      and erl.assignee_profile_id is not null
    order by erl.created_at, erl.id
    limit 1;
    if not found then
      v_assignee := null;
    end if;

    -- Task identity, fail-closed at every step:
    -- (1) the project's task already linked to this work;
    v_task_id := null;
    select t.id into v_task_id
    from public.tasks t
    where t.project_id = p_project_id and t.estimate_work_id = v_work.id;

    -- (2) else the task derived from checklist lineage (how the client itself
    --     rehydrates hero-created tasks whose tasks.estimate_work_id is NULL);
    if v_task_id is null then
      select count(distinct ci.task_id) into v_derived_count
      from public.task_checklist_items ci
      join public.tasks t on t.id = ci.task_id
      where ci.estimate_work_id = v_work.id
        and t.project_id = p_project_id
        and (t.estimate_work_id is null or t.estimate_work_id = v_work.id);
      if v_derived_count > 1 then
        raise exception 'ambiguous remote task mapping for estimate work %', v_work.id using errcode = 'P0001';
      end if;
      if v_derived_count = 1 then
        select distinct ci.task_id into v_task_id
        from public.task_checklist_items ci
        join public.tasks t on t.id = ci.task_id
        where ci.estimate_work_id = v_work.id
          and t.project_id = p_project_id
          and (t.estimate_work_id is null or t.estimate_work_id = v_work.id);
      end if;
    end if;

    -- (3) else the hero-transition task map, validated same-project +
    --     compatible lineage; a failed candidate is DISCARDED, never reused;
    if v_task_id is null and (v_hero_task_map->>v_work.id::text) is not null then
      v_candidate := (v_hero_task_map->>v_work.id::text)::uuid;
      select t.id into v_task_id
      from public.tasks t
      where t.id = v_candidate
        and t.project_id = p_project_id
        and (t.estimate_work_id is null or t.estimate_work_id = v_work.id);
    end if;

    -- (4) else the deterministic id = work id — validated if it collides.
    if v_task_id is null then
      v_task_id := v_work.id;
      select t.project_id, t.estimate_work_id into v_candidate_project, v_candidate_work
      from public.tasks t where t.id = v_task_id;
      if found and (
        v_candidate_project <> p_project_id
        or (v_candidate_work is not null and v_candidate_work <> v_work.id)
      ) then
        raise exception 'projection target id collision for task %', v_task_id using errcode = '22023';
      end if;
    end if;

    if v_task_map ? v_work.id::text then
      raise exception 'duplicate estimate work in projection' using errcode = '22023';
    end if;

    insert into public.tasks (
      id, project_id, stage_id, estimate_work_id, title, description, status,
      assignee_profile_id, created_by, start_at, due_at
    ) values (
      v_task_id, p_project_id, v_work.project_stage_id, v_work.id, v_work.title,
      'Auto-created from Estimate v2 work', 'not_started',
      v_assignee, v_uid, v_work.planned_start, v_work.planned_end
    )
    on conflict (id) do update set
      stage_id = excluded.stage_id,
      estimate_work_id = excluded.estimate_work_id,
      title = excluded.title,
      assignee_profile_id = excluded.assignee_profile_id,
      start_at = excluded.start_at,
      due_at = excluded.due_at
    -- Fail-closed: never adopt a row from another project (a concurrent
    -- hostile insert then surfaces as a FK/lineage error, not a takeover).
    where tasks.project_id = excluded.project_id;

    get diagnostics v_count = row_count;
    if v_count = 0 then
      raise exception 'projection target id collision for task %', v_task_id using errcode = '22023';
    end if;

    v_tasks_upserted := v_tasks_upserted + 1;
    v_task_map := v_task_map || jsonb_build_object(v_work.id::text, v_task_id::text);
    v_active_task_ids := array_append(v_active_task_ids, v_task_id);
  end loop;

  ------------------------------------------------------------------
  -- CHECKLIST: snapshot loaded rows first (preserved fields are read
  -- BEFORE deletions, matching the client), then delete stale/orphan/
  -- duplicate estimate-linked rows, two-phase renumber, upsert desired
  -- rows, re-pack manual rows after the estimate block.
  ------------------------------------------------------------------
  drop table if exists pg_temp.t_ci_loaded;
  create temp table t_ci_loaded on commit drop as
  select ci.id, ci.task_id, ci.title, ci.is_done, ci.procurement_item_id,
         ci.estimate_resource_line_id, ci.estimate_work_id, ci.sort_order
  from public.task_checklist_items ci
  where ci.task_id = any (v_active_task_ids || v_stale_task_ids);

  -- One winner per estimate line (no unique index exists on
  -- task_checklist_items.estimate_resource_line_id; duplicates are possible in
  -- legacy data). Losers are deleted below.
  drop table if exists pg_temp.t_ci_existing;
  create temp table t_ci_existing on commit drop as
  select distinct on (l.estimate_resource_line_id)
         l.estimate_resource_line_id as line_id, l.id, l.is_done, l.procurement_item_id
  from pg_temp.t_ci_loaded l
  where l.estimate_resource_line_id is not null
  order by l.estimate_resource_line_id, l.id;

  drop table if exists pg_temp.t_ci_desired;
  create temp table t_ci_desired on commit drop as
  select
    coalesce(ex.id, erl.id) as id,
    (v_task_map->>ew.id::text)::uuid as task_id,
    erl.title,
    coalesce(ex.is_done, false) as is_done,
    ex.procurement_item_id,
    erl.id as line_id,
    ew.id as work_id,
    (row_number() over (
      partition by ew.id
      order by
        case erl.resource_type
          when 'material' then 0 when 'tool' then 1 when 'labor' then 2
          when 'subcontractor' then 3 when 'overhead' then 4 else 5
        end,
        erl.id::text collate "C"
    ))::integer as sort_order
  from public.estimate_works ew
  join public.estimate_resource_lines erl on erl.estimate_work_id = ew.id
  left join pg_temp.t_ci_existing ex on ex.line_id = erl.id
  where ew.estimate_version_id = v_version_id
    and (v_task_map ? ew.id::text);

  -- Fail-closed: two desired rows sharing one id (a legacy row whose id equals
  -- a DIFFERENT line's uuid) would silently collapse last-wins in the upsert,
  -- transplanting is_done across lines. Ambiguity raises, mirroring the
  -- lineage-ambiguity raises above.
  for v_row in
    select d.id from pg_temp.t_ci_desired d group by d.id having count(*) > 1
  loop
    raise exception 'ambiguous checklist identity for item %', v_row.id using errcode = '22023';
  end loop;

  -- Fail-closed: a desired checklist id may already exist as a row of another
  -- project's task; adopting it would re-parent foreign data.
  for v_row in
    select d.id, d.line_id from pg_temp.t_ci_desired d
  loop
    select t.project_id into v_candidate_project
    from public.task_checklist_items ci
    join public.tasks t on t.id = ci.task_id
    where ci.id = v_row.id;
    if found and v_candidate_project <> p_project_id then
      raise exception 'projection target id collision for checklist item %', v_row.id using errcode = '22023';
    end if;
  end loop;

  -- Delete stale/orphan/duplicate estimate-linked rows among the LOADED set.
  with deleted as (
    delete from public.task_checklist_items ci
    using pg_temp.t_ci_loaded l
    where ci.id = l.id
      and (l.estimate_resource_line_id is not null or l.estimate_work_id is not null)
      and (
        l.estimate_work_id is null
        or not (v_task_map ? l.estimate_work_id::text)
        or l.estimate_resource_line_id is null
        or l.estimate_resource_line_id not in (select d.line_id from pg_temp.t_ci_desired d)
        -- lineage duplicates: every row for a desired line except the winner
        or exists (
          select 1 from pg_temp.t_ci_desired d
          where d.line_id = l.estimate_resource_line_id and d.id <> l.id
        )
      )
    returning ci.id
  )
  select count(*) into v_checklist_deleted from deleted;

  drop table if exists pg_temp.t_ci_retained;
  create temp table t_ci_retained on commit drop as
  select l.*
  from pg_temp.t_ci_loaded l
  where exists (select 1 from public.task_checklist_items ci where ci.id = l.id);

  -- Phase 1: move every retained row of each active task with desired rows to a
  -- collision-free temporary band above max(sort_order) + desired count.
  for v_task_id in select distinct d.task_id from pg_temp.t_ci_desired d loop
    select count(*) into v_desired_count from pg_temp.t_ci_desired d where d.task_id = v_task_id;
    select max(r.sort_order) into v_max_sort from pg_temp.t_ci_retained r where r.task_id = v_task_id;
    if v_max_sort is null then
      continue; -- no retained rows: fresh inserts take 1..N directly
    end if;
    v_index := 0;
    for v_row in
      select r.id from pg_temp.t_ci_retained r
      where r.task_id = v_task_id
      order by r.sort_order, r.id
    loop
      update public.task_checklist_items ci
      set sort_order = v_max_sort + v_desired_count + v_index + 1
      where ci.id = v_row.id;
      v_index := v_index + 1;
    end loop;
  end loop;

  -- Upsert desired rows at final positions 1..N per task.
  for v_row in
    select d.* from pg_temp.t_ci_desired d order by d.task_id, d.sort_order
  loop
    insert into public.task_checklist_items (
      id, task_id, title, is_done, procurement_item_id,
      estimate_resource_line_id, estimate_work_id, sort_order
    ) values (
      v_row.id, v_row.task_id, v_row.title, v_row.is_done, v_row.procurement_item_id,
      v_row.line_id, v_row.work_id, v_row.sort_order
    )
    on conflict (id) do update set
      task_id = excluded.task_id,
      title = excluded.title,
      estimate_resource_line_id = excluded.estimate_resource_line_id,
      estimate_work_id = excluded.estimate_work_id,
      sort_order = excluded.sort_order
    -- Fail-closed: only rows whose current task belongs to this project.
    where exists (
      select 1 from public.tasks t
      where t.id = task_checklist_items.task_id and t.project_id = p_project_id
    );

    get diagnostics v_count = row_count;
    if v_count = 0 then
      raise exception 'projection target id collision for checklist item %', v_row.id using errcode = '22023';
    end if;
    v_checklist_upserted := v_checklist_upserted + 1;
  end loop;

  -- Phase 2: pack retained MANUAL rows (no lineage) immediately after the
  -- estimate block, preserving their previous relative order.
  for v_task_id in select distinct d.task_id from pg_temp.t_ci_desired d loop
    select count(*) into v_desired_count from pg_temp.t_ci_desired d where d.task_id = v_task_id;
    v_index := 0;
    for v_row in
      select r.id from pg_temp.t_ci_retained r
      where r.task_id = v_task_id
        and r.estimate_resource_line_id is null
        and r.estimate_work_id is null
      order by r.sort_order, r.id
    loop
      update public.task_checklist_items ci
      set sort_order = v_desired_count + v_index + 1
      where ci.id = v_row.id;
      v_index := v_index + 1;
    end loop;
  end loop;

  ------------------------------------------------------------------
  -- PROCUREMENT: material/tool lines of every current work (no task
  -- requirement). Unlink stale lineage, then upsert by line identity.
  ------------------------------------------------------------------
  drop table if exists pg_temp.t_proc_lines;
  create temp table t_proc_lines on commit drop as
  select erl.id as line_id, erl.title, erl.quantity, erl.unit, erl.unit_price_cents,
         ew.id as work_id
  from public.estimate_works ew
  join public.estimate_resource_lines erl on erl.estimate_work_id = ew.id
  where ew.estimate_version_id = v_version_id
    and erl.resource_type in ('material', 'tool');

  with unlinked as (
    update public.procurement_items pi
    set estimate_resource_line_id = null, task_id = null
    where pi.project_id = p_project_id
      and pi.estimate_resource_line_id is not null
      and pi.estimate_resource_line_id not in (select pl.line_id from pg_temp.t_proc_lines pl)
    returning pi.id
  )
  select count(*) into v_procurement_unlinked from unlinked;

  for v_line in select pl.* from pg_temp.t_proc_lines pl order by pl.line_id loop
    v_existing_id := null;
    select pi.id into v_existing_id
    from public.procurement_items pi
    where pi.project_id = p_project_id and pi.estimate_resource_line_id = v_line.line_id;

    if v_existing_id is null and (v_hero_proc_map->>v_line.line_id::text) is not null then
      -- A candidate that fails this same-project validation is discarded.
      v_candidate := (v_hero_proc_map->>v_line.line_id::text)::uuid;
      select pi.id into v_existing_id
      from public.procurement_items pi
      where pi.id = v_candidate
        and pi.project_id = p_project_id
        and (pi.estimate_resource_line_id is null or pi.estimate_resource_line_id = v_line.line_id);
    end if;

    if v_existing_id is null then
      v_existing_id := v_line.line_id;
      select pi.project_id, pi.estimate_resource_line_id into v_candidate_project, v_candidate_line
      from public.procurement_items pi where pi.id = v_existing_id;
      if found and (
        v_candidate_project <> p_project_id
        or (v_candidate_line is not null and v_candidate_line <> v_line.line_id)
      ) then
        raise exception 'projection target id collision for procurement item %', v_existing_id using errcode = '22023';
      end if;
    end if;

    insert into public.procurement_items (
      id, project_id, estimate_resource_line_id, task_id, title, quantity, unit,
      planned_unit_price_cents, planned_total_price_cents, status, created_by
    ) values (
      v_existing_id, p_project_id, v_line.line_id,
      (v_task_map->>v_line.work_id::text)::uuid,
      v_line.title, greatest(0, v_line.quantity), v_line.unit,
      greatest(0, coalesce(v_line.unit_price_cents, 0)),
      round(greatest(0, coalesce(v_line.unit_price_cents, 0)) * greatest(0, v_line.quantity))::bigint,
      'requested', v_uid
    )
    on conflict (id) do update set
      estimate_resource_line_id = excluded.estimate_resource_line_id,
      task_id = excluded.task_id,
      title = excluded.title,
      quantity = excluded.quantity,
      -- A null estimate unit must not erase a human-maintained unit.
      unit = coalesce(excluded.unit, procurement_items.unit),
      planned_unit_price_cents = excluded.planned_unit_price_cents,
      planned_total_price_cents = excluded.planned_total_price_cents
    -- Fail-closed: never adopt a row from another project; created_by is
    -- insert-only (creator attribution is stable across re-projections).
    where procurement_items.project_id = excluded.project_id;

    get diagnostics v_count = row_count;
    if v_count = 0 then
      raise exception 'projection target id collision for procurement item %', v_existing_id using errcode = '22023';
    end if;
    v_procurement_upserted := v_procurement_upserted + 1;
  end loop;

  ------------------------------------------------------------------
  -- HR: labor/subcontractor lines whose work received a task. Unlink
  -- stale lineage (including hero-map legacy rows), upsert by line
  -- identity with lineage fallbacks, reconcile single assignee.
  ------------------------------------------------------------------
  drop table if exists pg_temp.t_hr_lines;
  create temp table t_hr_lines on commit drop as
  select erl.id as line_id, erl.title, erl.quantity, erl.unit_price_cents,
         erl.assignee_profile_id,
         ew.id as work_id, ew.project_stage_id,
         ew.planned_start, ew.planned_end,
         (v_task_map->>ew.id::text)::uuid as task_id
  from public.estimate_works ew
  join public.estimate_resource_lines erl on erl.estimate_work_id = ew.id
  where ew.estimate_version_id = v_version_id
    and erl.resource_type in ('labor', 'subcontractor')
    and (v_task_map ? ew.id::text);

  with unlinked as (
    update public.hr_items hi
    set estimate_resource_line_id = null, estimate_work_id = null, task_id = null
    where hi.project_id = p_project_id
      and hi.estimate_resource_line_id is not null
      and hi.estimate_resource_line_id not in (select hl.line_id from pg_temp.t_hr_lines hl)
    returning hi.id
  )
  select count(*) into v_hr_unlinked from unlinked;

  -- Legacy stale unlink: hero-map rows that kept only work/task lineage.
  for v_key, v_val in select * from jsonb_each_text(v_hero_hr_map) loop
    if v_key ~ c_uuid_re
       and not exists (select 1 from pg_temp.t_hr_lines hl where hl.line_id = v_key::uuid)
    then
      update public.hr_items hi
      set estimate_work_id = null, task_id = null
      where hi.id = v_val::uuid
        and hi.project_id = p_project_id
        and hi.estimate_resource_line_id is null
        and (hi.estimate_work_id is not null or hi.task_id is not null);
      get diagnostics v_count = row_count;
      v_hr_unlinked := v_hr_unlinked + v_count;
    end if;
  end loop;

  for v_line in select hl.* from pg_temp.t_hr_lines hl order by hl.line_id loop
    v_existing_id := null;
    select hi.id into v_existing_id
    from public.hr_items hi
    where hi.project_id = p_project_id and hi.estimate_resource_line_id = v_line.line_id;

    if v_existing_id is null and (v_hero_hr_map->>v_line.line_id::text) is not null then
      -- A candidate that fails this same-project validation is discarded (it
      -- is NOT reused as a new-row id below).
      v_candidate := (v_hero_hr_map->>v_line.line_id::text)::uuid;
      select hi.id into v_existing_id
      from public.hr_items hi
      where hi.id = v_candidate
        and hi.project_id = p_project_id
        and (hi.estimate_resource_line_id is null or hi.estimate_resource_line_id = v_line.line_id);
    end if;

    if v_existing_id is null then
      select count(*) into v_lineage_count
      from public.hr_items hi
      where hi.project_id = p_project_id
        and hi.estimate_resource_line_id is null
        and hi.estimate_work_id = v_line.work_id
        and hi.task_id = v_line.task_id
        and hi.title = v_line.title;
      if v_lineage_count > 1 then
        raise exception 'ambiguous remote hr mapping for estimate line %', v_line.line_id using errcode = 'P0001';
      end if;
      if v_lineage_count = 1 then
        select hi.id into v_existing_id
        from public.hr_items hi
        where hi.project_id = p_project_id
          and hi.estimate_resource_line_id is null
          and hi.estimate_work_id = v_line.work_id
          and hi.task_id = v_line.task_id
          and hi.title = v_line.title;
      end if;
    end if;

    if v_existing_id is null then
      v_existing_id := v_line.line_id;
      select hi.project_id, hi.estimate_resource_line_id into v_candidate_project, v_candidate_line
      from public.hr_items hi where hi.id = v_existing_id;
      if found and (
        v_candidate_project <> p_project_id
        or (v_candidate_line is not null and v_candidate_line <> v_line.line_id)
      ) then
        raise exception 'projection target id collision for hr item %', v_existing_id using errcode = '22023';
      end if;
    end if;

    insert into public.hr_items (
      id, project_id, project_stage_id, estimate_work_id, task_id,
      estimate_resource_line_id, title, planned_cost_cents, start_at, end_at, created_by
    ) values (
      v_existing_id, p_project_id, v_line.project_stage_id, v_line.work_id, v_line.task_id,
      v_line.line_id, v_line.title,
      greatest(0, round(coalesce(v_line.unit_price_cents, 0) * v_line.quantity))::bigint,
      v_line.planned_start, v_line.planned_end, v_uid
    )
    on conflict (id) do update set
      project_stage_id = excluded.project_stage_id,
      estimate_work_id = excluded.estimate_work_id,
      task_id = excluded.task_id,
      estimate_resource_line_id = excluded.estimate_resource_line_id,
      title = excluded.title,
      planned_cost_cents = excluded.planned_cost_cents,
      start_at = coalesce(excluded.start_at, hr_items.start_at),
      end_at = coalesce(excluded.end_at, hr_items.end_at)
    -- Fail-closed: never adopt a row from another project.
    where hr_items.project_id = excluded.project_id;

    get diagnostics v_count = row_count;
    if v_count = 0 then
      raise exception 'projection target id collision for hr item %', v_existing_id using errcode = '22023';
    end if;
    v_hr_upserted := v_hr_upserted + 1;

    -- Single-assignee reconcile: the line's profile assignee is the whole target
    -- set; a label-only or unassigned line clears the assignees.
    delete from public.hr_item_assignees ha
    where ha.hr_item_id = v_existing_id
      and (v_line.assignee_profile_id is null or ha.profile_id <> v_line.assignee_profile_id);
    if v_line.assignee_profile_id is not null then
      insert into public.hr_item_assignees (hr_item_id, profile_id)
      values (v_existing_id, v_line.assignee_profile_id)
      on conflict (hr_item_id, profile_id) do nothing;
    end if;
  end loop;

  ------------------------------------------------------------------
  -- Finalize: bump the server projection counter and emit the ledger event.
  ------------------------------------------------------------------
  update public.project_estimates pe
  set projection_revision = p_client_revision,
      projection_seq = pe.projection_seq + 1,
      projection_synced_at = now(),
      projection_actor = v_uid
  where pe.id = v_root.id
  returning pe.projection_seq into v_projection_seq;

  insert into public.project_sync_events (project_id, kind, revision, actor_profile_id)
  values (p_project_id, 'projection', p_client_revision, v_uid);

  return jsonb_build_object(
    'status', 'projected',
    'revision', p_client_revision,
    'projection_seq', v_projection_seq,
    'task_id_by_work_id', v_task_map,
    'skipped_work_ids', to_jsonb(v_skipped_work_ids),
    'counts', jsonb_build_object(
      'tasks_upserted', v_tasks_upserted,
      'tasks_unlinked', v_tasks_unlinked,
      'checklist_upserted', v_checklist_upserted,
      'checklist_deleted', v_checklist_deleted,
      'procurement_upserted', v_procurement_upserted,
      'procurement_unlinked', v_procurement_unlinked,
      'hr_upserted', v_hr_upserted,
      'hr_unlinked', v_hr_unlinked
    )
  );
end;
$$;

revoke all on function public.sync_estimate_projection(uuid, text) from public;
grant execute on function public.sync_estimate_projection(uuid, text) to authenticated;
grant execute on function public.sync_estimate_projection(uuid, text) to service_role;

-- Atomic replacement for the client's SELECT-then-INSERT ensureEstimateCurrentVersion
-- (two sessions could both see zero current versions; the loser surfaced a raw
-- unique-index violation). Shares the projection's advisory lock key so a
-- version flip and a projection for the same project always serialize.
-- Absent and unauthorized identifiers return one uniform not-found error (no
-- cross-tenant existence oracle).
drop function if exists public.set_estimate_current_version(uuid, uuid);

create function public.set_estimate_current_version(
  p_estimate_id uuid,
  p_version_id uuid
) returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_uid uuid := auth.uid();
  v_project_id uuid;
  v_current_id uuid;
  v_target_estimate uuid;
  v_next_number integer;
begin
  if v_uid is null then
    raise exception 'must be authenticated' using errcode = '42501';
  end if;
  if p_estimate_id is null or p_version_id is null then
    raise exception 'invalid version arguments' using errcode = '22023';
  end if;

  -- Authorization-scoped lookup: an estimate that does not exist and one the
  -- caller may not manage are indistinguishable.
  select pe.project_id into v_project_id
  from public.project_estimates pe
  where pe.id = p_estimate_id
    and public.can_manage_project(pe.project_id);
  if v_project_id is null then
    raise exception 'estimate not found' using errcode = 'P0002';
  end if;

  -- Same lock key as sync_estimate_projection: flips and projections serialize.
  perform pg_advisory_xact_lock(hashtext('sync_estimate_projection:' || v_project_id::text));

  select ev.id into v_current_id
  from public.estimate_versions ev
  where ev.estimate_id = p_estimate_id and ev.is_current = true;

  if v_current_id = p_version_id then
    return jsonb_build_object('status', 'unchanged', 'version_id', p_version_id);
  end if;

  select ev.estimate_id into v_target_estimate
  from public.estimate_versions ev
  where ev.id = p_version_id;

  -- A version of another estimate and a stale/unknown id both surface as the
  -- same mismatch signal (no existence oracle across estimates).
  if v_target_estimate is not null and v_target_estimate <> p_estimate_id then
    raise exception 'current version id mismatch' using errcode = 'P0001';
  end if;

  if v_target_estimate is null and v_current_id is not null then
    raise exception 'current version id mismatch' using errcode = 'P0001';
  end if;

  if v_current_id is not null then
    update public.estimate_versions ev set is_current = false where ev.id = v_current_id;
  end if;

  if v_target_estimate is null then
    select coalesce(max(ev.version_number), 0) + 1 into v_next_number
    from public.estimate_versions ev
    where ev.estimate_id = p_estimate_id;
    insert into public.estimate_versions (id, estimate_id, version_number, is_current, created_by)
    values (p_version_id, p_estimate_id, v_next_number, true, v_uid);
    return jsonb_build_object('status', 'created', 'version_id', p_version_id, 'version_number', v_next_number);
  end if;

  update public.estimate_versions ev set is_current = true where ev.id = p_version_id;
  return jsonb_build_object('status', 'flipped', 'version_id', p_version_id);
end;
$$;

revoke all on function public.set_estimate_current_version(uuid, uuid) from public;
grant execute on function public.set_estimate_current_version(uuid, uuid) to authenticated;
grant execute on function public.set_estimate_current_version(uuid, uuid) to service_role;
